1	const PROCESSING_FEE = 5;
2	const COMPONENT_PREMIUM = 25;
3	const COMPONENT_BLOCK_PREMIUM = 60;
4	const COMPONENT_BLOCK_SIZE = 3;
5	
6	const MAIN_ITEM_PREMIUMS: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	};
12	
13	function isComponent(type: string): boolean {
14	  return !(type in MAIN_ITEM_PREMIUMS);
15	}
16	
17	function computeComponentPremium(items: any[]): number {
18	  const componentCounts: Record<string, number> = {};
19	
20	  for (const item of items) {
21	    if (isComponent(item.type)) {
22	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
23	    }
24	  }
25	
26	  let premium = 0;
27	  for (const count of Object.values(componentCounts)) {
28	    premium += count === COMPONENT_BLOCK_SIZE
29	      ? COMPONENT_BLOCK_PREMIUM
30	      : count * COMPONENT_PREMIUM;
31	  }
32	  return premium;
33	}
34	
35	function computeMainItemPremium(items: any[]): number {
36	  let premium = 0;
37	  for (const item of items) {
38	    if (!isComponent(item.type)) {
39	      let itemPremium = MAIN_ITEM_PREMIUMS[item.type];
40	      if (item.cursed) {
41	        itemPremium += itemPremium * 0.5;
42	      }
43	      premium += itemPremium;
44	    }
45	  }
46	  return premium;
47	}
48	
49	function computeBasePremium(items: any[]): number {
50	  return computeMainItemPremium(items) + computeComponentPremium(items);
51	}
52	
53	export function processScenario(scenario: any): any {
54	  const step = scenario.steps[0];
55	  const basePremium = computeBasePremium(step.items);
56	  return { results: [{ premium: basePremium + PROCESSING_FEE }] };
57	}
